#include <bits/stdc++.h>
using namespace std;

int main() {
    ios_base::sync_with_stdio(false); cin.tie(NULL);
    int m; cin >> m;
    int mask = 0;
    while (m--) {
        string op; cin >> op;
        if (op == "add") { int x; cin >> x; mask |= (1 << x); }
        else if (op == "remove") { int x; cin >> x; mask &= ~(1 << x); }
        else if (op == "check") { int x; cin >> x; cout << ((mask >> x) & 1) << "\n"; }
        else { cout << __builtin_popcount(mask) << "\n"; }
    }
    return 0;
}
